 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;
 using Microsoft.Extensions.Logging;
 using ModelContextProtocol.Server;

 /// <summary>
 /// MCP tools that wrap the JSONPlaceholder REST API via HttpClient.
 /// Uses constructor injection — the SDK resolves HttpClient and ILogger
 /// from DI automatically; they never appear in the tool schema.
 /// </summary>
 [McpServerToolType]
 internal sealed class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

     [McpServerTool, Description("List posts from the API. Optionally filter by user ID.")]
     public async Task<string> ListPosts(
         [Description("User ID to filter posts by (omit for all posts)")] int? userId = null,
         CancellationToken cancellationToken = default)
     {
         var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
         logger.LogInformation("GET {Url}", url);

         var posts = await httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);
         return posts.ValueKind == JsonValueKind.Array
             ? $"Found {posts.GetArrayLength()} post(s):\n{JsonSerializer.Serialize(posts, JsonOptions)}"
             : posts.ToString();
     }

     [McpServerTool, Description("Get a single post by its ID.")]
     public async Task<string> GetPost(
         [Description("The numeric ID of the post to retrieve")] int id,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("GET /posts/{Id}", id);

         var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
         if (!response.IsSuccessStatusCode)
             return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";

         var post = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
         return JsonSerializer.Serialize(post, JsonOptions);
     }

     [McpServerTool(Destructive = false, ReadOnly = true),
      Description("Search posts whose title or body contains the given query text.")]
     public async Task<string> SearchPosts(
         [Description("Text to search for in post titles and bodies")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Searching posts for '{Query}'", query);

         var posts = await httpClient.GetFromJsonAsync<JsonElement[]>("/posts", cancellationToken)
             ?? [];

         var matches = posts.Where(p =>
             (p.GetProperty("title").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false) ||
             (p.GetProperty("body").GetString()?.Contains(query, StringComparison.OrdinalIgnoreCase) ?? false))
             .ToArray();

         return matches.Length == 0
             ? "No posts matched your query."
             : $"Found {matches.Length} matching post(s):\n{JsonSerializer.Serialize(matches, JsonOptions)}";
     }

     [McpServerTool(Destructive = false, ReadOnly = false),
      Description("Create a new post. Returns the created post with its assigned ID.")]
     public async Task<string> CreatePost(
         [Description("Title of the new post")] string title,
         [Description("Body content of the new post")] string body,
         [Description("Author's user ID")] int userId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("POST /posts (userId={UserId})", userId);

         var payload = new { title, body, userId };
         var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);

         if (!response.IsSuccessStatusCode)
             return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";

         var created = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
         return $"Post created:\n{JsonSerializer.Serialize(created, JsonOptions)}";
     }
 }

